// Mode: Run Once For All Items
// Normalise les fichiers: files, files0, files1... -> binary.data
// et conserve le JSON (dont sessionId)

const src = items[0] || { json: {}, binary: {} };
const bin = src.binary || {};
const baseJson = src.json || {};

const out = [];

for (const [k, v] of Object.entries(bin)) {
  // ne garder que les clés "files", "files0", "files1", ...
  if (/^files(\d+)?$/.test(k)) {
    out.push({
      json: { ...baseJson, fileKey: k },
      binary: { data: v }, // <- clé stable pour la suite
    });
  }
}

// Si rien trouvé, tu peux retourner [] (pas d'items) ou l'item d'origine.
// Comme tu es sur la branche "has files ? = true", en principe out.length > 0.
return out.length ? out : [];

