//-------------------------------------------------------
// 1. Récupération de la réponse OpenAI
//-------------------------------------------------------
let raw = $json.message?.content || "";

// Nettoyage des blocs markdown
raw = raw
  .replace(/```json/gi, "")
  .replace(/```/g, "")
  .trim();

// Extraction du premier JSON valide
const match = raw.match(/\{[\s\S]*\}/);
if (!match) {
  throw new Error("Aucun JSON détecté dans la réponse : " + raw);
}

const jsonString = match[0];

// Parsing sûr
let parsed;
try {
  parsed = JSON.parse(jsonString);
} catch (e) {
  throw new Error("Le JSON extrait est invalide : " + jsonString);
}

//-------------------------------------------------------
// 2. Extraction du texte
//-------------------------------------------------------
const text = parsed.text_extracted || "";

//-------------------------------------------------------
// 3. IOC extraction
//-------------------------------------------------------
const urls = [...new Set(text.match(/https?:\/\/[^\s"]+/gi) || [])];
const emails = [...new Set(text.match(/[a-z0-9._%+-]+@[a-z0-9.-]+\.[a-z]{2,}/gi) || [])];
const phones = [...new Set(text.match(/\+?\d[\d\s().-]{7,}/gi) || [])];

//-------------------------------------------------------
// 4. Retour propre
//-------------------------------------------------------
return {
  json: {
    ...parsed,
    ioc: {
      urls,
      emails,
      phones
    }
  },
  binary: $item.binary  // <-- le bon accès en mode "Run Once for Each Item"
};

// Ce node lit le binaire "data" depuis le disque et produit une Data URL correcte
const out = [];
for (let i = 0; i < items.length; i++) {
  const bin = items[i].binary?.data;
  if (!bin) throw new Error('Pas de binaire "data" sur l’item.');

  // Récupère le buffer depuis le stockage (filesystem-v2, s3, etc.)
  const buf = await this.helpers.getBinaryDataBuffer(i, 'data');

  const mime = bin.mimeType || 'image/png';
  const b64  = buf.toString('base64');

  out.push({
    json: { imageDataUrl: `data:${mime};base64,${b64}` }
  });
}
return out;
return [{ json: { ...$json }, binary: $binary }];

// Node Code n8n — version correcte avec async/await

const results = [];

for (let i = 0; i < items.length; i++) {

  const item = items[i];
  const bin = item.binary?.data;

  if (!bin) {
    throw new Error('Pas de binaire "data" sur cet item.');
  }

  // Charge le buffer réel du fichier (PDF, Word, TXT…)
  const buffer = await this.helpers.getBinaryDataBuffer(i, 'data');

  const mime = bin.mimeType || 'application/octet-stream';
  const base64 = buffer.toString('base64');

  results.push({
    json: {
      fileBase64: base64,
      fileName: bin.fileName,
      mimeType: mime,
      dataUrl: `data:${mime};base64,${base64}`
    },
    binary: item.binary  // On garde le binaire intact
  });
}

return results;

