// Scoring initial
let score = 0;

// -------------------------------
// 1. Score VirusTotal
// -------------------------------
const vt = $json.vt || {};

if (vt.malicious > 0) score += 60;
if (vt.suspicious > 0) score += 40;
if (vt.harmless === 0 && vt.undetected === 0) score += 10;

// -------------------------------
// 2. IOC techniques
// -------------------------------
const ioc = $json.ioc || {};

if ((ioc.urls || []).length > 0) score += 10;
if ((ioc.emails || []).length > 0) score += 10;
if ((ioc.phones || []).length > 0) score += 5;

// -------------------------------
// 3. Analyse contextuelle
// -------------------------------
if ($json.global_risk_level === "élevé") score += 30;
if ($json.global_risk_level === "moyen") score += 15;

if (($json.risk_signals || []).length >= 3) score += 15;
else if (($json.risk_signals || []).length > 0) score += 5;

// -------------------------------
// 4. Normalisation du score
// -------------------------------
if (score > 100) score = 100;

// -------------------------------
// 5. Catégorie finale
// -------------------------------
let category = "faible";
if (score >= 70) category = "élevé";
else if (score >= 40) category = "moyen";

// -------------------------------
// 6. Retour n8n
// -------------------------------
return {
  json: {
    ...$json,
    risk_score: score,
    risk_category: category
  },
  binary: $item.binary
};

const item = items[0].json;

function normalize(str = "") {
  return (str + "")
    .toLowerCase()
    .normalize("NFD").replace(/[\u0300-\u036f]/g, "") // retire accents
    .replace(/[^\p{L}\p{N}\s]/gu, " ")               // ponctuation -> espaces
    .replace(/\s+/g, " ")
    .trim();
}

// match mot entier (évite que "cb" match "cbon")
function hasWord(text, w) {
  const escaped = w.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
  const re = new RegExp(`(^|\\s)${escaped}(\\s|$)`, "i");
  return re.test(text);
}

// match expression (plus permissif)
function hasPhrase(text, phrase) {
  return text.includes(phrase);
}

const raw = item.transcript || item.chatInput || "";
const text = normalize(raw);

// Signaux forts (plus discriminants)
const strongSignals = {
  url: /(https?:\/\/|www\.)\S+/i.test(raw) || hasWord(text, "http") || hasWord(text, "www"),
  iban: /\b[a-z]{2}\d{2}[a-z0-9]{11,30}\b/i.test(raw) || hasWord(text, "iban"),
  otp: /\b(otp|2fa)\b/i.test(raw) || /\b\d{4,8}\b/.test(raw) && (hasWord(text, "code") || hasWord(text, "verification")),
  colisBrand: /(chronopost|mondial\s?relay|dpd|ups|fedex|laposte|colissimo)/i.test(raw),
  bankWords: /(virement|transaction|paiement|carte|cb|banque)/i.test(raw),
  emailWords: /(mail|e-mail|piece jointe|facture|pdf|document|boite mail)/i.test(text),
  hackedWords: /(pirat|hacker|compte|mot de passe|connexion)/i.test(text),
  techSupportWords: /(microsoft|apple|support|technicien|virus|ordinateur bloque|appel)/i.test(text),
};

// Règles améliorées : keywords + poids + signaux forts + anti-signaux optionnels
const rules = [
  {
    intent: "fraude_bancaire",
    base: 0.55,
    tags: ["banque"],
    keywords: [
      { k: "virement", w: 1.4 }, { k: "iban", w: 1.8 }, { k: "transaction", w: 1.2 },
      { k: "paiement", w: 1.2 }, { k: "carte", w: 1.0 }, { k: "cb", w: 1.0 },
      { k: "banque", w: 1.2 }, { k: "otp", w: 1.8 }, { k: "code", w: 0.7 }
    ],
    strong: () => (strongSignals.iban ? 0.25 : 0) + (strongSignals.bankWords ? 0.15 : 0) + (strongSignals.otp ? 0.12 : 0),
    anti: ["colis", "livraison"],
  },
  {
    intent: "smishing_colis",
    base: 0.52,
    tags: ["sms", "colis"],
    keywords: [
      { k: "colis", w: 1.6 }, { k: "livraison", w: 1.4 }, { k: "sms", w: 1.2 },
      { k: "suivi", w: 1.0 }, { k: "relais", w: 1.0 }, { k: "frais", w: 0.9 }
    ],
    strong: () => (strongSignals.colisBrand ? 0.28 : 0) + (hasPhrase(text, "mondial relay") ? 0.10 : 0),
    anti: ["iban", "banque", "virement"],
  },
  {
    intent: "phishing_email",
    base: 0.50,
    tags: ["email"],
    keywords: [
      { k: "mail", w: 1.3 }, { k: "e mail", w: 1.3 }, { k: "piece jointe", w: 1.6 },
      { k: "facture", w: 1.4 }, { k: "pdf", w: 1.2 }, { k: "document", w: 1.1 },
      { k: "boite mail", w: 1.6 }
    ],
    strong: () => (strongSignals.emailWords ? 0.22 : 0) + (strongSignals.url ? 0.10 : 0),
    anti: ["colis", "livraison"],
  },
  {
    intent: "compte_piratage",
    base: 0.50,
    tags: ["compte"],
    keywords: [
      { k: "pirate", w: 1.6 }, { k: "pirate", w: 1.6 }, { k: "pirate", w: 1.6 },
      { k: "hacker", w: 1.6 }, { k: "compte", w: 1.2 }, { k: "mot de passe", w: 1.6 },
      { k: "connexion", w: 1.2 }, { k: "code de securite", w: 1.2 }
    ],
    strong: () => (strongSignals.hackedWords ? 0.25 : 0),
    anti: ["colis", "facture"],
  },
  {
    intent: "arnaque_support_tech",
    base: 0.48,
    tags: ["support"],
    keywords: [
      { k: "microsoft", w: 1.7 }, { k: "apple", w: 1.7 }, { k: "support", w: 1.2 },
      { k: "technicien", w: 1.4 }, { k: "virus", w: 1.4 }, { k: "ordinateur bloque", w: 1.6 },
      { k: "appel", w: 0.8 }
    ],
    strong: () => (strongSignals.techSupportWords ? 0.28 : 0),
    anti: ["iban", "virement"],
  },
  {
    intent: "lien_suspect",
    base: 0.45,
    tags: ["lien"],
    keywords: [
      { k: "lien", w: 1.3 }, { k: "url", w: 1.4 }, { k: "clique", w: 1.2 },
      { k: "site", w: 0.9 }, { k: "http", w: 1.6 }, { k: "www", w: 1.3 }
    ],
    strong: () => (strongSignals.url ? 0.35 : 0),
    anti: [],
  }
];

// scoring
function scoreRule(rule) {
  let matched = [];
  let hitWeight = 0;

  for (const kw of rule.keywords) {
    const kNorm = normalize(kw.k);
    const ok = kNorm.includes(" ") ? hasPhrase(text, kNorm) : hasWord(text, kNorm);
    if (ok) {
      matched.push(kw.k);
      hitWeight += kw.w;
    }
  }

  // anti-signaux : petite pénalité si on trouve des mots qui "pull" ailleurs
  let antiPenalty = 0;
  for (const a of (rule.anti || [])) {
    const aNorm = normalize(a);
    if (aNorm.includes(" ") ? hasPhrase(text, aNorm) : hasWord(text, aNorm)) {
      antiPenalty += 0.08;
    }
  }

  // densité: plus il y a de hits, plus on est sûr, mais avec saturation
  const density = Math.min(0.25, hitWeight * 0.06);

  // bonus multi-indices : plusieurs mots distincts = meilleur signal
  const multi = matched.length >= 3 ? 0.12 : matched.length === 2 ? 0.06 : 0;

  const strong = rule.strong ? rule.strong() : 0;

  // score brut
  let score = rule.base + density + multi + strong - antiPenalty;

  // clamp 0..0.97
  score = Math.max(0, Math.min(0.97, score));

  return { intent: rule.intent, score, tags: rule.tags, matched };
}

// compute top2 + ambiguity penalty
const ranked = rules.map(scoreRule).sort((a, b) => b.score - a.score);
const top = ranked[0];
const second = ranked[1];

// si aucun mot matché et aucun strong signal => unknown
const hasAnySignal = top.matched.length > 0 || top.score > 0.65; // 0.65 couvre url/iban etc.
let finalIntent = hasAnySignal ? top.intent : "unknown";
let finalConfidence = hasAnySignal ? top.score : 0;

// pénalité ambiguïté : si le 2e est proche, on baisse la confiance
if (finalIntent !== "unknown") {
  const gap = top.score - second.score; // 0..1
  if (gap < 0.08) finalConfidence = Math.max(0.45, finalConfidence - 0.18);
  else if (gap < 0.15) finalConfidence = Math.max(0.50, finalConfidence - 0.10);
}

// ajoute un petit debug utile
return [{
  json: {
    ...item,
    intent_rules: finalIntent,
    confidence_rules: Number(finalConfidence.toFixed(2)),
    tags_rules: finalIntent === "unknown" ? [] : top.tags,
    debug_rules: {
      text_used: text,
      top: top,
      second: second,
      gap: Number((top.score - second.score).toFixed(2)),
      strongSignals,
    }
  }
}];

