let current_mode = "collect_info";

// ordre de priorité
if (clickedOrShared) {
  current_mode = "protect_after_click";
} else if (asksEducational) {
  current_mode = "educational";
} else if (asksStarter) {
  current_mode = "starter";
} else if (asksSafeGuidance) {
  current_mode = "safe_guidance";
} else if (asksLinkCheck) {
  current_mode = "verdict";
} else if (definitelyOutOfScope) {
  current_mode = "out_of_scope";
} else if (isVeryVague) {
  current_mode = "collect_info";
}

return [{
  json: {
    ...$json,
    current_mode
  }
}];

