parameters.jsCode:
const transcript = ($json.transcript || "").trim();
const raw = transcript;
const text = raw.toLowerCase().normalize("NFD").replace(/[\u0300-\u036f]/g, "");

function firstMatch(regex, str) {
  const m = str.match(regex);
  return m ? m[0] : null;
}

const source_type =
  /sms/.test(text) ? "sms" :
  /mail|e-mail|email/.test(text) ? "email" :
  /appel|telephone|téléphone/.test(text) ? "call" :
  /site|lien|url|www|http/.test(text) ? "website" :
  /application|appli|app/.test(text) ? "app" :
  null;

const url_or_domain =
  firstMatch(/\bhttps?:\/\/[^\s]+/i, raw) ||
  firstMatch(/\b(?:[a-z0-9-]+\.)+[a-z]{2,}\b/i, raw);

const user_clicked =
  /j['’]ai cliqu|j['’]ai ouvert le lien/.test(text) ? "yes" :
  /je n['’]ai pas cliqu|je n['’]ai pas ouvert/.test(text) ? "no" :
  null;

const user_shared_info =
  /j['’]ai donn|j['’]ai saisi|j['’]ai entr|j['’]ai partage/.test(text) ? "yes" :
  /je n['’]ai rien donn|je n['’]ai rien saisi|je n['’]ai rien partage/.test(text) ? "no" :
  null;

const expected_message =
  /j['’]attendais|c['’]etait prevu|c['’]était prévu/.test(text) ? "yes" :
  /je n['’]attendais pas|ce n['’]etait pas prevu|ce n['’]était pas prévu/.test(text) ? "no" :
  null;

const sender_id =
  firstMatch(/[A-Z0-9._%+-]+@[A-Z0-9.-]+\.[A-Z]{2,}/i, raw) ||
  firstMatch(/\b\d{5,15}\b/, raw);

return [{
  json: {
    ...$json,
    source_type,
    sender_id,
    url_or_domain,
    user_clicked,
    user_shared_info,
    expected_message
  }
}];

const mode = $json.current_mode || "collect_info";

const facts = {
  source_type: $json.source_type || null,
  sender_id: $json.sender_id || null,
  url_or_domain: $json.url_or_domain || null,
  user_clicked: $json.user_clicked || null,
  user_shared_info: $json.user_shared_info || null,
  expected_message: $json.expected_message || null,
};

let missing_priority = [];
let should_ask_question = false;

// Si clic ou partage : priorité à l'action, pas à la collecte
if (mode === "protect_after_click") {
  missing_priority = [];
  should_ask_question = false;
}

// Si on est en mode éducatif / guidance / tool result : pas besoin de question par défaut
else if (["educational", "safe_guidance", "tool_result"].includes(mode)) {
  missing_priority = [];
  should_ask_question = false;
}

// Si on est en verdict et qu'on a déjà un lien/domaine, on peut répondre sans question
else if (mode === "verdict" && facts.url_or_domain) {
  missing_priority = [];
  should_ask_question = false;
}

// Collecte : un seul manque prioritaire
else if (mode === "collect_info") {
  if (!facts.source_type) missing_priority = ["source_type"];
  else if (!facts.sender_id && !facts.url_or_domain) missing_priority = ["sender_or_link"];
  else if (!facts.expected_message) missing_priority = ["expected_message"];
  else missing_priority = [];

  should_ask_question = missing_priority.length > 0;
}

return [{
  json: {
    ...$json,
    missing_priority,
    should_ask_question
  }
}];

const mode = $('Build Ernest Context').item.json.current_mode || "collect_info";

let text =
  $json.output ??
  $json.response ??
  $json.text ??
  $json.answer ??
  "";

text = String(text).trim();

// Si plus d'une question, on garde seulement la première
const questionMatches = text.match(/\?/g) || [];
if (questionMatches.length > 1) {
  let seen = 0;
  let result = "";
  for (const ch of text) {
    result += ch;
    if (ch === "?") {
      seen += 1;
      if (seen >= 1) break;
    }
  }
  // on garde seulement ce qui précède ou contient la première question
  text = result.trim();
}

// En modes où la question n'est pas nécessaire, on retire les relances génériques
if (["educational", "safe_guidance", "tool_result", "verdict"].includes(mode)) {
  text = text.replace(/\s*(Voulez-vous|Souhaitez-vous|Avez-vous|Je peux aussi)[^?]*\?\s*$/i, "").trim();
}

return [{
  json: {
    ...$json,
    output: text
  }
}];
